#!/usr/bin/env node
// Select and install the correct RTK binary for the current platform.
// Copies the matching pre-built binary from bin/rtk-<platform>-<arch> to bin/rtk.
// bin/rtk is gitignored — it is always generated by this script.

import { copyFileSync, chmodSync, existsSync, readFileSync, writeFileSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))

const platform = process.platform // 'darwin', 'linux', 'win32'
const arch = process.arch         // 'arm64', 'x64'

const binaryMap = {
  'darwin-arm64': 'rtk-darwin-arm64',
  'darwin-x64':   'rtk-darwin-x64',
  'linux-x64':    'rtk-linux-x64',
  'win32-x64':    'rtk-win32-x64.exe',
}

const key = `${platform}-${arch}`
const srcName = binaryMap[key]

if (!srcName) {
  console.warn(`[copy-rtk] No RTK binary for ${key} — skipping. Supported: ${Object.keys(binaryMap).join(', ')}`)
  console.warn(`[copy-rtk] RTK filtering will not be available. The app will work without it.`)
  process.exit(0)
}

const src = join(__dirname, srcName)
const isWindows = platform === 'win32'
const dest = join(__dirname, isWindows ? 'rtk.exe' : 'rtk')
const versionDest = join(__dirname, 'rtk-version.txt')

if (!existsSync(src)) {
  console.warn(`[copy-rtk] Missing binary: ${src} — skipping RTK install.`)
  console.warn(`[copy-rtk] RTK filtering will not be available. The app will work without it.`)
  process.exit(0)
}

copyFileSync(src, dest)
if (!isWindows) chmodSync(dest, 0o755)

// Write version info
try {
  const version = readFileSync(join(__dirname, 'rtk-version.txt'), 'utf-8').trim()
  writeFileSync(versionDest, version)
  console.log(`[copy-rtk] Installed rtk v${version} (${srcName}) → ${dest}`)
} catch {
  console.log(`[copy-rtk] Installed ${srcName} → ${dest}`)
}
